@namespace sv_4ca6aec5ad7549edbd7992b722580c7d.Components.Pages.Board
@using sv_4ca6aec5ad7549edbd7992b722580c7d.Services

<div class="card border-secondary mb-2 p-2">
    <div class="d-flex justify-content-between align-items-center">
        <div>
            <strong>@Task.Title</strong>
            <br />
            <small class="text-muted">@Task.Assignee</small>
        </div>
        <span class="badge @PriorityClass">@Task.Priority</span>
    </div>
    <div class="d-flex justify-content-between align-items-center mt-2">
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div>
            @if (CanMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary me-1" @onclick="() => OnMoveLeft.InvokeAsync(Task)" disabled="@IsMoving">
                    &larr;
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="() => OnMoveRight.InvokeAsync(Task)" disabled="@IsMoving">
                    &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@namespace sv_4ca6aec5ad7549edbd7992b722580c7d.Components.Pages.Board
@using sv_4ca6aec5ad7549edbd7992b722580c7d.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body d-flex flex-column gap-2" style="min-height: 200px;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight"
                          IsMoving="IsMoving" />
            }

            @if (_showForm)
            {
                <div class="card border-primary p-2">
                    <div class="mb-2">
                        <input class="form-control form-control-sm" placeholder="Title" @bind="_newTitle" />
                    </div>
                    <div class="mb-2">
                        <input class="form-control form-control-sm" placeholder="Assignee" @bind="_newAssignee" />
                    </div>
                    <div class="mb-2">
                        <select class="form-select form-select-sm" @bind="_newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                    </div>
                    <div class="mb-2">
                        <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
                    </div>
                    <div class="d-flex gap-1">
                        <button class="btn btn-sm btn-primary" @onclick="SaveTask" disabled="@_isSaving">Save</button>
                        <button class="btn btn-sm btn-outline-secondary" @onclick="CancelForm" disabled="@_isSaving">Cancel</button>
                    </div>
                </div>
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="ShowForm" disabled="@_showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private bool _showForm;
    private bool _isSaving;
    private string _newTitle = "";
    private string _newAssignee = "";
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today;

    private void ShowForm() => _showForm = true;

    private void CancelForm()
    {
        _showForm = false;
        ResetForm();
    }

    private async Task SaveTask()
    {
        if (string.IsNullOrWhiteSpace(_newTitle)) return;

        _isSaving = true;
        try
        {
            await OnAddTask.InvokeAsync((_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate, ColumnName));
            _showForm = false;
            ResetForm();
        }
        finally
        {
            _isSaving = false;
        }
    }

    private void ResetForm()
    {
