                      OnMoveRight="@(t => MoveTask(t, "In Progress"))"
                      OnAddTask="HandleAddTask"
                      IsMoving="_isMoving" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="@GetColumnTasks("In Progress", _filteredTasks)"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="@(t => MoveTask(t, "To Do"))"
                      OnMoveRight="@(t => MoveTask(t, "Done"))"
                      OnAddTask="HandleAddTask"
                      IsMoving="_isMoving" />

        <KanbanColumn ColumnName="Done"
                      Tasks="@GetColumnTasks("Done", _filteredTasks)"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
                      OnAddTask="HandleAddTask"
                      IsMoving="_isMoving" />
    </div>
}

@code {
    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private bool _isMoving;
    private string? _error;
    private string _searchTerm = "";

    private List<TaskItem> _filteredTasks =>
        string.IsNullOrWhiteSpace(_searchTerm)
            ? _allTasks
            : _allTasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private static List<TaskItem> GetColumnTasks(string status, List<TaskItem> tasks) =>
        tasks.Where(t => t.Status == status).ToList();

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        _isMoving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _isMoving = false;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) newTask)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
            if (created.Status != newTask.Status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, newTask.Status);
            }
            await LoadTasks();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

