+            }
+        </div>
+        <div class="card-footer">
+            <button class="btn btn-sm btn-outline-primary w-100" @onclick="ShowForm" disabled="@_showForm">
+                + Add Task
+            </button>
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
+    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
+    [Parameter] public bool CanMoveLeft { get; set; }
+    [Parameter] public bool CanMoveRight { get; set; }
+    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
+    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
+    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }
+    [Parameter] public bool IsMoving { get; set; }
+
+    private bool _showForm;
+    private bool _isSaving;
+    private string _newTitle = "";
+    private string _newAssignee = "";
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today;
+
+    private void ShowForm() => _showForm = true;
+
+    private void CancelForm()
+    {
+        _showForm = false;
+        ResetForm();
+    }
+
+    private async Task SaveTask()
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle)) return;
+
+        _isSaving = true;
+        try
+        {
+            await OnAddTask.InvokeAsync((_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate, ColumnName));
+            _showForm = false;
+            ResetForm();
+        }
+        finally
+        {
+            _isSaving = false;
+        }
+    }
+
+    private void ResetForm()
+    {
+        _newTitle = "";
+        _newAssignee = "";
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today;
+    }
+}
